local _cachedLang = nil
local _cachedLangTable = nil
T = function(key)
    if currentLang ~= _cachedLang then
        _cachedLang = currentLang
        _cachedLangTable = LANGS[currentLang]
    end
    if _cachedLangTable and _cachedLangTable[key] ~= nil then
        return tostring(_cachedLangTable[key])
    end
    local en = LANGS.en
    if en and en[key] ~= nil then return tostring(en[key]) end
    return key
end
